z7n3mof.css:
display: flex;
  flex-direction: column;
  gap: calc(var(--content-gap, 1rem) / 2);
  position: relative;
  justify-content: center;

  &::before {
    content: '';
    inline-size: 100%;
    block-size: 1.5px;
    background: color-mix(in oklch, var(--black, #000) 10%, transparent);
    position: absolute;
    left: 0;
    top: calc(var(--card-gap) * -0.5);
  }

  @container (inline-size >= to-rem(800px)) {
    /* # Vertical Divider Line */
    &::before {
      content: '';
      block-size: calc(100% + var(--card-padding));
      inline-size: 1.5px;
      top: 50%;
      translate: 0% -50%;
      left: calc(var(--card-gap) * -0.5);
    }
  }

